#include <iostream>#include <algorithm> using namespace std; bool check(long long n, long long s, long long m) {    if (n < 0) return false;    for (int i = 60; i >= 0; i--) {       if ((m >> i) & 1) {            long long bitValue = (1LL << i);                long long take = min(n, s / bitValue);                s -= take * bitValue;        }    }    return s == 0;}   int main() {    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin >> t;    while (t--) {        long long s, m;        cin >> s >> m;         if (s > 0 && m == 0) {            cout << -1 << "\n";        }         else if (s % (m & -m) != 0) {            cout << -1 << "\n";        }        else{            long long low = 1, high = 2e18;             long long ans = -1;             while (low <= high) {                long long mid = low + (high - low) / 2;                if (check(mid, s, m)) {                ans = mid;                high = mid - 1;                 } else {                    low = mid + 1;                  }            }             cout << ans << "\n";        }    }    return 0;}